record_types.code:
type Answer_Record is
   record
      Value : Binding_Type;
      Next  : Solution;
   end record;

type Atom_Record (Pclass : Predtype) is record
   Oclass : Optype;
   Oprec  : Prec;
   Sys    : Boolean;
   case Pclass is
      when Normp => Proc : Clptr;
      when Evalp =>
         Routine : Evalpred;
         Arity   : Evalarity;
   end case;
end record;

type Binding_Type is
   record
      Id : Acc_String;
      C  : Term;
   end record;

type Cls is record
   Head     : Term;
   The_Body : Term;
   Typ      : Cls_Type;
   Nvars    : Integer;
   Keyval   : Integer;
   Dbase    : Integer;
   Previous : Clptr;
   Next     : Clptr;
end record;

type Integer_Record is record
   I    : Integer;
   Next : Integer_List;
end record;

type Node (Tag : Nodetag) is record
   Brother : Term;
   Field   : Field_Type;
   Scope   : Integer;
   Chain   : Term;
   case Tag is
      when Funct =>
         Name  : Atom;
         Arity : Integer;
         Son   : Term;
      when Intt =>
         Ival : Integer;
      when Vart =>
         Val : Term;
         Id  : Varstring;
      when Skelt =>
         Offset : Integer;
         St     : Varstring;
         Anont  : Boolean;
   end case;
end record;

